mapper.select:
select paper_id, paper_name, paper_type, course_name, rule_desc, question_count, status, avg_score, update_time, created_at, updated_at, created_by, updated_by, deleted from practice_papers
and deleted = false
and (paper_name like concat('%', #{keyword}, '%') or course_name like concat('%', #{keyword}, '%'))
and status = #{status}
order by paper_id desc limit #{pageSize} offset #{offset}

mapper.insert:
insert into practice_papers (
  paper_name, paper_type, course_name, rule_desc, question_count, status, avg_score, update_time,
  created_at, updated_at, created_by, updated_by, deleted
)
values (
  #{paperName}, #{paperType}, #{courseName}, #{ruleDesc}, #{questionCount}, #{status}, #{avgScore}, #{updateTime},
  #{createdAt}, #{updatedAt}, #{createdBy}, #{updatedBy}, #{deleted}
)

mapper.update:
update practice_papers
set deleted = true,
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where paper_id = #{paperId}
  and deleted = false
